// Stand-in for client.send(...) on a live socket:
function pushSocket(userid, message) {
    console.log('\ud83d\udd0c socket \u2192 user ' + userid + ': ' + message);
}

var beto = { id: 2, email: 'beto@example.com' };   // online
var caro = { id: 3, email: 'caro@example.com' };   // offline

function notify(user, message) {
    // online? pushSocket(user.id, message)   else   MAIL(user.email, 'New task for you', message)
}

notify(beto, 'Ada shared "Buy milk" with you');
notify(caro, 'Ada shared "Buy milk" with you');

